import React, { useState, useEffect } from 'react';

function Dice({ value, rolling }) {
  // Simple dice faces as Unicode dots (⚀ ⚁ ⚂ ⚃ ⚄ ⚅)
  // Or you can replace with images if you want
  const diceFaces = ['\u2680', '\u2681', '\u2682', '\u2683', '\u2684', '\u2685'];

  return (
    <div
      style={{
        fontSize: '80px',
        width: '100px',
        height: '100px',
        lineHeight: '100px',
        textAlign: 'center',
        border: '3px solid #000',
        borderRadius: '15px',
        margin: '0 10px',
        userSelect: 'none',
        backgroundColor: rolling ? '#f0f0f0' : '#fff',
        transition: 'background-color 0.3s',
        boxShadow: rolling ? '0 0 10px 3px #888' : 'none',
      }}
    >
      {rolling ? '?' : diceFaces[value - 1]}
    </div>
  );
}

function App() {
  const [player, setPlayer] = useState('');
  const [position, setPosition] = useState(0);
  const [turn, setTurn] = useState(1);
  const [rotation, setRotation] = useState(0);

  // Dice rolling states
  const [rolling, setRolling] = useState(false);
  const [dice1, setDice1] = useState(1);
  const [dice2, setDice2] = useState(1);

  const rotateBoard = () => {
    setRotation((prev) => (prev + 90) % 360);
  };

  const rollDice = () => {
    if (rolling) return; // prevent double clicks

    setRolling(true);

    // Animate dice for 1 second
    let animationCount = 0;
    const animationInterval = setInterval(() => {
      setDice1(Math.floor(Math.random() * 6) + 1);
      setDice2(Math.floor(Math.random() * 6) + 1);
      animationCount++;
      if (animationCount >= 10) {
        clearInterval(animationInterval);
        setRolling(false);

        // Set final dice values
        const finalDice1 = Math.floor(Math.random() * 6) + 1;
        const finalDice2 = Math.floor(Math.random() * 6) + 1;
        setDice1(finalDice1);
        setDice2(finalDice2);

        // Update player position and turn
        const total = finalDice1 + finalDice2;
        setPosition((pos) => (pos + total) % 20);
        setTurn((t) => t + 1);
      }
    }, 100);
  };

  return (
    <div style={{ padding: 20, fontFamily: 'Arial', maxWidth: '700px', margin: 'auto' }}>
      <h1>Monopoly Starter Game</h1>

      <div
        style={{
          maxWidth: '600px',
          marginBottom: '20px',
          border: '2px solid #000',
          display: 'inline-block',
          transform: `rotate(${rotation}deg)`,
          transition: 'transform 0.5s ease',
        }}
      >
        <img
          src={`${process.env.PUBLIC_URL}/torahpoly_board.png`}
          alt="Monopoly Board"
          style={{ maxWidth: '100%', height: 'auto', display: 'block' }}
        />
      </div>

      <div>
        <button
          onClick={rotateBoard}
          style={{ padding: '10px 20px', fontSize: '16px', marginBottom: '20px', cursor: 'pointer' }}
        >
          Rotate Board
        </button>
      </div>

      <input
        placeholder="Enter your player name"
        value={player}
        onChange={(e) => setPlayer(e.target.value)}
        style={{ padding: '8px', fontSize: '16px', width: '100%', maxWidth: '300px', marginBottom: '10px' }}
      />

      <p>Turn: {turn}</p>
      <p>Player: {player || 'No player yet'}</p>
      <p>Position: {position}</p>

      <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '20px' }}>
        <Dice value={dice1} rolling={rolling} />
        <Dice value={dice2} rolling={rolling} />
      </div>

      <button
        onClick={rollDice}
        style={{ padding: '10px 20px', fontSize: '16px', cursor: rolling ? 'not-allowed' : 'pointer' }}
        disabled={rolling}
      >
        {rolling ? 'Rolling...' : 'Roll Dice'}
      </button>

      <p>(Board and cards will be added later.)</p>
    </div>
  );
}

export default App;
